import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.Pywvta2k.js";const u=JSON.parse('{"title":"卢崇汉（火神派）","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/05-近现代/09-卢崇汉（火神派）.md","filePath":"tcm-data/05-近现代/09-卢崇汉（火神派）.md","lastUpdated":1781084559000}'),o={name:"tcm-data/05-近现代/09-卢崇汉（火神派）.md"};function n(s,t,d,i,h,g){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="卢崇汉-火神派" tabindex="-1">卢崇汉（火神派） <a class="header-anchor" href="#卢崇汉-火神派" aria-label="Permalink to &quot;卢崇汉（火神派）&quot;">​</a></h1><blockquote><p>卢崇汉（1947年生），四川成都人 火神派第三代传人，扶阳学派代表人物 代表作：《扶阳讲记》《卢氏汤方》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>师承</strong>：卢铸之（祖父）→ 卢永定（伯父）→ 卢崇汉</li><li><strong>流派</strong>：火神派（扶阳学派）</li><li><strong>现任</strong>：成都中医药大学教授</li><li><strong>学术地位</strong>：<strong>火神派正统传人</strong>，&quot;扶阳&quot;思想的核心推动者</li></ul><h3 id="火神派的传承脉络" tabindex="-1">火神派的传承脉络 <a class="header-anchor" href="#火神派的传承脉络" aria-label="Permalink to &quot;火神派的传承脉络&quot;">​</a></h3><p><strong>郑钦安（1824-1911年）</strong> → 卢铸之（1876-1963年）→ 卢永定（1912-1985年）→ <strong>卢崇汉</strong></p><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-扶阳-——-火神派的核心" tabindex="-1">1. 扶阳 —— 火神派的核心 <a class="header-anchor" href="#_1-扶阳-——-火神派的核心" aria-label="Permalink to &quot;1. 扶阳 —— 火神派的核心&quot;">​</a></h3><blockquote><p><strong>「人生立命，以火立极。治病立法，必以扶阳为要。」</strong></p></blockquote><p>卢崇汉认为：<strong>阳气是生命的主宰</strong>，阳气一衰，百病丛生。</p><h3 id="_2-阴阳辨诀" tabindex="-1">2. 阴阳辨诀 <a class="header-anchor" href="#_2-阴阳辨诀" aria-label="Permalink to &quot;2. 阴阳辨诀&quot;">​</a></h3><blockquote><p><strong>「阳证易辨，阴证难识。」</strong></p></blockquote><p>卢崇汉特别强调辨别<strong>阴证</strong>的重要性：</p><ul><li>面色虽红但眼光无神 → 阴证浮阳（真寒假热）</li><li>口渴但不欲饮 → 阴证</li><li>烦躁但脉沉细 → 阴证</li></ul><p><strong>这与患者的&quot;口渴不贪凉&quot;完全吻合。</strong></p><h3 id="_3-临床特色" tabindex="-1">3. 临床特色 <a class="header-anchor" href="#_3-临床特色" aria-label="Permalink to &quot;3. 临床特色&quot;">​</a></h3><p>卢崇汉临床用药以<strong>附子、干姜、肉桂、麻黄、桂枝</strong>等温热药为主：</p><ul><li>附子用量常在30-90g</li><li>遇到阴盛格阳证，附子可用到100-200g</li></ul><h3 id="_4-常用药对" tabindex="-1">4. 常用药对 <a class="header-anchor" href="#_4-常用药对" aria-label="Permalink to &quot;4. 常用药对&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">药对</th><th style="text-align:left;">功效</th></tr></thead><tbody><tr><td style="text-align:left;">附子+干姜</td><td style="text-align:left;">温阳第一组合</td></tr><tr><td style="text-align:left;">附子+肉桂</td><td style="text-align:left;">引火归原</td></tr><tr><td style="text-align:left;">附子+黄芪</td><td style="text-align:left;">温阳益气</td></tr><tr><td style="text-align:left;">麻黄+附子</td><td style="text-align:left;">扶阳解表（太少两感）</td></tr></tbody></table><hr><h2 id="三、代表方剂" tabindex="-1">三、代表方剂 <a class="header-anchor" href="#三、代表方剂" aria-label="Permalink to &quot;三、代表方剂&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>四逆汤类方</strong></td><td style="text-align:left;">附子、干姜、甘草</td><td style="text-align:left;">少阴寒化</td></tr><tr><td style="text-align:left;"><strong>麻黄附子细辛汤</strong></td><td style="text-align:left;">麻黄、附子、细辛</td><td style="text-align:left;">太少两感</td></tr><tr><td style="text-align:left;"><strong>桂枝法系列</strong></td><td style="text-align:left;">桂枝为主的各种加减</td><td style="text-align:left;">太阳风寒、风湿</td></tr><tr><td style="text-align:left;"><strong>潜阳丹</strong></td><td style="text-align:left;">附子、龟板、砂仁、甘草</td><td style="text-align:left;">虚阳上浮</td></tr><tr><td style="text-align:left;"><strong>封髓丹</strong></td><td style="text-align:left;">黄柏、砂仁、甘草</td><td style="text-align:left;">相火妄动（口疮、遗精）</td></tr></tbody></table><hr><h2 id="四、经典名言" tabindex="-1">四、经典名言 <a class="header-anchor" href="#四、经典名言" aria-label="Permalink to &quot;四、经典名言&quot;">​</a></h2><blockquote><p><strong>「人生立命，以火立极。治病立法，必以扶阳为要。」</strong></p></blockquote><blockquote><p><strong>「阳证易辨，阴证难识。」</strong></p></blockquote><blockquote><p><strong>「万病皆因阳虚。」</strong>（继承郑钦安）</p></blockquote><blockquote><p><strong>「附子为扶阳第一品药。」</strong></p></blockquote><blockquote><p><strong>「阴盛则阳衰，阳衰则病生。」</strong></p></blockquote><hr><h2 id="五、火神派与其他流派的关系" tabindex="-1">五、火神派与其他流派的关系 <a class="header-anchor" href="#五、火神派与其他流派的关系" aria-label="Permalink to &quot;五、火神派与其他流派的关系&quot;">​</a></h2><h3 id="火神派-vs-黄元御" tabindex="-1">火神派 vs 黄元御 <a class="header-anchor" href="#火神派-vs-黄元御" aria-label="Permalink to &quot;火神派 vs 黄元御&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">火神派（卢崇汉）</th><th style="text-align:left;">黄元御</th></tr></thead><tbody><tr><td style="text-align:left;">核心</td><td style="text-align:left;">扶阳，重用附子</td><td style="text-align:left;">崇阳，但不唯附子</td></tr><tr><td style="text-align:left;">中气</td><td style="text-align:left;">中气也源于肾阳</td><td style="text-align:left;">中气是枢轴</td></tr><tr><td style="text-align:left;">用药</td><td style="text-align:left;">附桂姜为常药</td><td style="text-align:left;">参姜苓草为轴心</td></tr><tr><td style="text-align:left;">共同点</td><td style="text-align:left;">都认为阳虚是万病之源</td><td style="text-align:left;">都强调扶阳抑阴</td></tr></tbody></table><h3 id="火神派-vs-李可" tabindex="-1">火神派 vs 李可 <a class="header-anchor" href="#火神派-vs-李可" aria-label="Permalink to &quot;火神派 vs 李可&quot;">​</a></h3><p>李可虽不是火神派嫡传，但用药思路与火神派高度一致（大剂量附子）。区别在于李可更侧重&quot;破格&quot;（急危重症），火神派更系统（理论体系完整）。</p><hr><h2 id="六、对患者的参考" tabindex="-1">六、对患者的参考 <a class="header-anchor" href="#六、对患者的参考" aria-label="Permalink to &quot;六、对患者的参考&quot;">​</a></h2><p>患者处方&quot;温潜黄芽天魂汤&quot;中的<strong>附子9g</strong>用量，与火神派的30-90g相比偏保守。但考虑到：</p><ol><li>首次用药</li><li>有肝肾功能损伤</li><li>上热下寒需&quot;温潜&quot;而非纯温</li></ol><p><strong>先9g起步是稳妥的做法。</strong></p><hr><p><em>本条目为精简框架版。可扩展至火神派与温补派对比、郑钦安医学思想专题等。</em></p>',45)])])}const x=e(o,[["render",n]]);export{u as __pageData,x as default};
